function PetProfile() {
    // Effect hook to set the document title when the component mounts.
    useEffect(() => {
        document.title = "MISHTIKA - Pet Profile";
    }, []);

    // State for storing the list of pets.
    const [pets, setPets] = useState([]);
    // State for storing error messages.
    const [error, setError] = useState('');
    // Retrieves the authentication token from local storage.
    const token = localStorage.getItem('token');

    // Function to fetch the current user's pets from the backend.
    const fetchPets = async () => {
        setError('');
        try {
            const decodedToken = JSON.parse(atob(token.split('.')[1]));
            const ownerId = decodedToken.id;
            const response = await api.get(`/pets/owner/${ownerId}`);
            setPets(response.data);
        } catch (error) {
            setError('Failed to fetch pets.');
        }
    };

    // Effect hook to fetch pets when the component mounts or the token changes.
    useEffect(() => {
        fetchPets();
    }, [token]);

    // Function to handle the deletion of a pet.
    const handleDelete = async (petId) => {
        if (!window.confirm(`Are you sure you want to delete this pet?`)) {
            return;
        }
        setError('');
        try {
            await api.delete(`/pets/${petId}`);
            setPets(pets.filter(p => p._id !== petId));
        } catch (error) {
            setError('Failed to delete pet.');
        }
    };

    // Framer Motion constraints
    const containerVariants = {
        hidden: { opacity: 0 },
        show: {
            opacity: 1,
            transition: { staggerChildren: 0.1 }
        }
    };

    const itemVariants = {
        hidden: { opacity: 0, y: 20 },
        show: { opacity: 1, y: 0, transition: { type: "spring", stiffness: 300, damping: 24 } }
    };

    return (
        <motion.div 
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -10 }}
            className="w-full"
        >
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-8">
                 <div>
                    <h1 className="text-3xl font-heading font-bold text-brandText tracking-tight">Your Pets</h1>
                    <p className="text-brandText-muted mt-1">Manage and view your furry companions' details.</p>
                 </div>
                 <Link to="/petform" className="flex items-center gap-2 px-6 py-3 bg-primary text-white font-medium rounded-full shadow-sm shadow-primary/30 hover:bg-primary-hover hover:-translate-y-0.5 hover:shadow-md transition-all">
                     <Plus size={18} /> Add Pet
                 </Link>
            </div>

            {/* Displays error messages if any. */}
            {error && (
                <motion.div 
                    initial={{ opacity: 0, scale: 0.98 }} 
                    animate={{ opacity: 1, scale: 1 }} 
                    className="mb-8 p-4 bg-red-50 border border-red-100 text-red-600 rounded-2xl flex items-center gap-3"
                >
                    <Info size={20} />
                    <p className="font-medium">{error}</p>
                </motion.div>
            )}

            {/* Message displayed if the user has no pets and no error occurred. */}
            {pets.length === 0 && !error && (
                <motion.div 
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="flex flex-col items-center justify-center p-16 bg-surface rounded-3xl border border-dashed border-gray-200 text-center"
                >
                    <div className="w-24 h-24 bg-gray-50 rounded-full flex items-center justify-center text-gray-300 mb-6 shadow-inner">
                        <PawPrint size={48} />
                    </div>
                    <h3 className="text-xl font-heading font-semibold text-brandText mb-2">No pets found</h3>
                    <p className="text-brandText-muted mb-8 max-w-sm text-lg">You haven't added any pets yet. Setup their profile to start managing their schedule and health!</p>
                    <Link to="/petform" className="flex items-center gap-2 px-6 py-3 bg-background border-2 border-gray-100 text-brandText font-medium rounded-full hover:border-primary hover:text-primary transition-all">
                        <Plus size={18} /> Add Your First Pet
                    </Link>
                </motion.div>
            )}

            {/* List of pets mapped to elevated cards. */}
            <motion.div 
                variants={containerVariants}
                initial="hidden"
                animate="show"
                className="grid grid-cols-1 lg:grid-cols-2 gap-6"
            >
                {pets.map((pet) => (
                    <motion.div 
                        key={pet._id} 
                        variants={itemVariants}
                        className="bg-surface rounded-3xl p-6 shadow-sm border border-gray-100 hover:shadow-md transition-shadow group flex flex-col sm:flex-row gap-6 relative overflow-hidden"
                    >
                        {/* Soft decorative glow in the background of the card */}
                        <div className="absolute -top-16 -right-16 w-40 h-40 bg-secondary/5 rounded-full blur-3xl group-hover:bg-secondary/10 transition-colors pointer-events-none" />

                        {/* Pet Avatar Placeholder */}
                        <div className="flex-shrink-0 flex justify-center sm:block">
                            <div className="w-32 h-32 bg-gradient-to-br from-amber-50 to-orange-50 border-4 border-white shadow-sm rounded-full flex items-center justify-center text-primary/40 relative z-10 group-hover:scale-105 transition-transform duration-300">
                                <PawPrint size={48} className="drop-shadow-sm" />
                            </div>
                        </div>

                        {/* Pet Information Display */}
                        <div className="flex-grow flex flex-col justify-between relative z-10 text-center sm:text-left">
                            <div>
                                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3 mb-4">
                                    <div>
                                        <h2 className="text-2xl font-heading font-bold text-brandText">{pet.name}</h2>
                                        <div className="flex items-center justify-center sm:justify-start gap-1.5 text-secondary font-medium mt-1">
                                            <PawPrint size={14} />
                                            <span>{pet.species} • {pet.breed}</span>
                                        </div>
                                    </div>
                                    <div className="inline-flex self-center sm:self-start items-center px-4 py-1.5 bg-background text-brandText-muted rounded-full text-xs font-semibold tracking-wider uppercase border border-gray-100 shadow-sm">
                                        {pet.gender}
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 gap-3 mb-4">
                                    <div className="flex items-center gap-3 text-sm text-brandText bg-background rounded-2xl p-2.5 border border-gray-50">
                                        <div className="p-2 bg-secondary/10 text-secondary rounded-xl">
                                            <Weight size={18} />
                                        </div>
                                        <span className="font-semibold">{pet.weight} <span className="text-brandText-muted font-normal">kg</span></span>
                                    </div>
                                    <div className="flex items-center gap-3 text-sm text-brandText bg-background rounded-2xl p-2.5 border border-gray-50">
                                        <div className="p-2 bg-accent/20 text-yellow-600 rounded-xl">
                                            <Calendar size={18} />
                                        </div>
                                        <span className="font-semibold">{pet.ageYears}<span className="text-brandText-muted font-normal">y</span> {pet.ageMonths}<span className="text-brandText-muted font-normal">m</span></span>
                                    </div>
                                </div>

                                {/* Medical information (if available) */}
                                {pet.medicalInfo && (
                                    <div className="mt-2 text-sm text-brandText bg-red-50/50 rounded-2xl p-3.5 border border-red-50 flex gap-3 items-start">
                                        <Activity size={18} className="text-red-400 mt-0.5 flex-shrink-0" />
                                        <p className="leading-relaxed"><strong className="text-red-700 font-semibold block mb-0.5">Medical Note</strong> {pet.medicalInfo}</p>
                                    </div>
                                )}
                            </div>

                            {/* Action Buttons */}
                            <div className="flex items-center gap-3 mt-6 pt-4 border-t border-gray-100">
                                <Link to={`/editpet/${pet._id}`} className="flex-1">
                                    <button className="w-full flex items-center justify-center gap-2 px-4 py-2.5 bg-background border border-gray-200 text-brandText rounded-xl text-sm font-semibold hover:border-primary hover:text-primary hover:shadow-sm transition-all">
                                        <Edit3 size={16} /> Edit Profile
                                    </button>
                                </Link>
                                <button 
                                    onClick={() => handleDelete(pet._id)}
                                    className="flex-shrink-0 p-2.5 text-brandText-muted hover:text-white hover:bg-red-500 rounded-xl transition-all border border-gray-200 hover:border-red-500 hover:shadow-sm"
                                    title="Delete Pet"
                                >
                                    <Trash2 size={18} />
                                </button>
                            </div>
                        </div>
                    </motion.div>
                ))}
            </motion.div>
        </motion.div>
    );
}

